func endpointBaseURL(ep *transport.Endpoint) string {
	if ep == nil || ep.Host == "" {
		return ""
	}
	scheme := ep.Protocol
	if scheme == "" {
		scheme = "https"
	}
	host := ep.Host
	if ep.Port > 0 {
		host = fmt.Sprintf("%s:%d", host, ep.Port)
	}
	return scheme + "://" + host
}

